        numbers.push_back(i * 2);
    }
    // Highlighted section 3: Display the sequence in a formatted way
    cout << "Number Sequence: " << endl;
    for (int i = 0; i < length; ++i) {
        cout << numbers[i] << " ";
    }
    cout << endl;
}

int main() {
    int rows = 5, cols = 10, length = 10;
    int numSequence[length];

    // Generate the number sequence
    generateNumberSequence(length);

    // Fill the numSequence array
    for (int i = 0; i < length; ++i) {
        numSequence[i] = i + 1;
    }

    // Generate the pattern
    generatePattern(rows, cols, numSequence);

    return 0;
}
